","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import "./HomePage.css";

interface HomeProps {
 navigateToView: (view: string, id?: string) => void;
}

const QUICK_ACTIONS = [
 { icon: "🎫", label: "Book Ticket", view: "book-ticket" },
 { icon: "🎓", label: "Student Pass", view: "student-pass" },
 { icon: "📋", label: "My Tickets", view: "my-tickets" },
 { icon: "📝", label: "Raise Complaint", view: "complaint" }
];

export default function HomePage({ navigateToView }: HomeProps) {
 const [stats, setStats] = useState({ stations: 0, routes: 0, passes: 0 });

 useEffect(() => {
 async function fetchStats() {
 try {
 const [stations, routes, passes] = await Promise.all([
 MetroService.list("x_1877508_metro_0_metro_stations", "active=true"),
 MetroService.list("x_1877508_metro_0_metro_routes", "active=true"),
 MetroService.list("x_1877508_metro_0_metro_student_pass", "pass_status=active")
 ]);
 setStats({ stations: stations.length, routes: routes.length, passes: passes.length });
 } catch (e) {
 console.error("Failed to fetch stats", e);
 }
 }
 fetchStats();
 }, []);

 return (
 <div className="metro-home">
 <div className="metro-home__banner">
 <h1 className="metro-home__title">Welcome to Metro Ticket Booking System</h1>
 <p className="metro-home__subtitle">
 Fast, reliable, and affordable metro travel. Book tickets, apply for student passes,
 and manage your journeys all in one place.
 </p>
 </div>

 <section className="metro-home__actions">
 <h2 className="metro-home__section-title">Quick Actions</h2>
 <div className="metro-home__cards">
 {QUICK_ACTIONS.map(action => (
 <button
 key={action.view}
 className="metro-home__card"
 onClick={() => navigateToView(action.view)}
 >
 <span className="metro-home__card-icon">{action.icon}</span>
 <span className="metro-home__card-label">{action.label}</span>
 </button>
 ))}
 </div>
 </section>

 <section className="metro-home__stats">
 <h2 className="metro-home__section-title">Metro Statistics</h2>
 <div className="metro-home__stats-grid">
 <div className="metro-home__stat">
 <span className="metro-home__stat-value">{stats.stations}</span>
 <span className="metro-home__stat-label">Total Stations</span>
 </div>
 <div className="metro-home__stat">
 <span className="metro-home__stat-value">{stats.routes}</span>
 <span className="metro-home__stat-label">Total Routes</span>
 </div>
 <div className="metro-home__stat">
 <span className="metro-home__stat-value">{stats.passes}</span>
 <span className="metro-home__stat-label">Active Passes</span>
 </div>
 </div>
 </section>
 </div>
 );
}
","export const display = (field: any): string => {
 if (field === null || field === undefined) return "";
 if (typeof field === "object") return field.display_value || "";
 return String(field);
};

export const value = (field: any): string => {
 if (field === null || field === undefined) return "";
 if (typeof field === "object") return field.value || "";
 return String(field);
};
","import React, { useState } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import { Station } from "./BookTicket";

interface FormProps {
 stations: Station[];
 passengerId: string;
 navigateToView: (view: string, id?: string) => void;
}

export default function BookTicketForm({ stations, passengerId, navigateToView }: FormProps) {
 const [source, setSource] = useState("");
 const [destination, setDestination] = useState("");
 const [travelDate, setTravelDate] = useState("");
 const [passengers, setPassengers] = useState(1);
 const [fare, setFare] = useState<any>(null);
 const [fareLoading, setFareLoading] = useState(false);
 const [submitting, setSubmitting] = useState(false);
 const [error, setError] = useState("");

 async function calculateFare(src: string, dest: string) {
 if (!src || !dest || src === dest) { setFare(null); return; }
 setFareLoading(true);
 try {
 const result = await MetroService.getFare(src, dest);
 setFare(result);
 } catch { setFare(null); }
 finally { setFareLoading(false); }
 }

 function handleSourceChange(val: string) {
 setSource(val);
 calculateFare(val, destination);
 }

 function handleDestChange(val: string) {
 setDestination(val);
 calculateFare(source, val);
 }

 async function handleSubmit(e: React.FormEvent) {
 e.preventDefault();
 setError("");
 if (!source || !destination || !travelDate) { setError("All fields are required"); return; }
 if (source === destination) { setError("Source and destination must differ"); return; }
 setSubmitting(true);
 try {
 const result = await MetroService.create("x_1877508_metro_0_metro_booking", {
 passenger: passengerId,
 source_station: source,
 destination_station: destination,
 journey_date: travelDate,
 passenger_count: passengers,
 fare_amount: fare ? value(fare.fare_amount) : "0"
 });
 navigateToView("ticket-details", value(result.sys_id));
 } catch { setError("Booking failed. Please try again."); }
 finally { setSubmitting(false); }
 }

 return (
 <form className="metro-book__form" onSubmit={handleSubmit}>
 {error && <div className="metro-book__error">{error}</div>}
 <label className="metro-book__label">Source Station
 <select className="metro-book__select" value={source} onChange={e => handleSourceChange(e.target.value)}>
 <option value="">Select station</option>
 {stations.map(s => <option key={value(s.sys_id)} value={value(s.sys_id)}>{display(s.station_name)}</option>)}
 </select>
 </label>
 <label className="metro-book__label">Destination Station
 <select className="metro-book__select" value={destination} onChange={e => handleDestChange(e.target.value)}>
 <option value="">Select station</option>
 {stations.map(s => <option key={value(s.sys_id)} value={value(s.sys_id)}>{display(s.station_name)}</option>)}
 </select>
 </label>
 <label className="metro-book__label">Travel Date
 <input className="metro-book__input" type="date" value={travelDate} onChange={e => setTravelDate(e.target.value)} />
 </label>
 <label className="metro-book__label">Number of Passengers
 <input className="metro-book__input" type="number" min={1} max={10} value={passengers} onChange={e => setPassengers(Number(e.target.value))} />
 </label>
 {fareLoading && <p className="metro-book__fare-loading">Calculating fare...</p>}
 {fare && !fareLoading && (
 <div className="metro-book__fare-preview">
 <span>Fare: ₹{display(fare.fare_amount)}</span>
 <span>Distance: {display(fare.distance_km)} km</span>
 <span>Est. Time: {display(fare.travel_time_min)} min</span>
 </div>
 )}
 <button className="metro-book__submit" type="submit" disabled={submitting}>
 {submitting ? "Booking..." : "Book Ticket"}
 </button>
 </form>
 );
}
","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { value } from "../utils/fields";
import BookTicketForm from "./BookTicketForm";
import "./BookTicket.css";

interface BookTicketProps {
 navigateToView: (view: string, id?: string) => void;
}

export interface Station {
 sys_id: { value: string };
 station_name: { display_value: string };
}

export default function BookTicket({ navigateToView }: BookTicketProps) {
 const [stations, setStations] = useState<Station[]>([]);
 const [passengerId, setPassengerId] = useState("");
 const [loading, setLoading] = useState(true);

 useEffect(() => {
 async function init() {
 try {
 const [stationList, passenger] = await Promise.all([
 MetroService.getStations(),
 MetroService.getPassengerByUser()
 ]);
 setStations(stationList);
 if (passenger) setPassengerId(value(passenger.sys_id));
 } catch (e) {
 console.error("Init failed", e);
 } finally {
 setLoading(false);
 }
 }
 init();
 }, []);

 if (loading) {
 return (
 <div className="metro-book">
 <h1 className="metro-book__title">Book Metro Ticket</h1>
 <p className="metro-book__loading">Loading...</p>
 </div>
 );
 }

 return (
 <div className="metro-book">
 <h1 className="metro-book__title">Book Metro Ticket</h1>
 <BookTicketForm
 stations={stations}
 passengerId={passengerId}
 navigateToView={navigateToView}
 />
 </div>
 );
}
","import React, { useState, useEffect } from "react";
import { MetroService } from "../services/MetroService";
import { display, value } from "../utils/fields";
import "./StudentPass.css";

interface StudentPassProps {
 navigateToView: (view: string, id?: string) => void;
}

export default function StudentPass({ navigateToView }: StudentPassProps) {
 const [stations, setStations] = useState<any[]>([]);
 const [passType, setPassType] = useState("monthly");
 const [source, setSource] = useState("");
 const [destination, setDestination] = useState("");
 const [fare, setFare] = useState<any>(null);
 const [submitting, setSubmitting] = useState(false);
 const [success, setSuccess] = useState(false);
 const [error, setError] = useState("");

 useEffect(() => {
 MetroService.getStations().then(setStations).catch(console.error);
 }, []);

 useEffect(() => {
 if (source && destination && source !== destination) {
 MetroService.getFare(source, destination).then(setFare).catch(() => setFare(null));
 } else { setFare(null); }
 }, [source, destination]);

 async function handleSubmit(e: React.FormEvent) {
 e.preventDefault();
 setError("");
 if (!source || !destination) { setError("All fields are required"); return; }
 if (source === destination) { setError("Stations must differ"); return; }
 setSubmitting(true);
 try {
 await MetroService.create("x_1877508_metro_0_metro_student_pass", {
 pass_type: passType,
 source_station: source,
 destination_station: destination
 });
 setSuccess(true);
 } catch { setError("Submission failed. Please try again."); }
 finally { setSubmitting(false); }
 }

 if (success) {
 return (
 <div className="metro-spass">
 <div className="metro-spass__success">
 <h2>✅ Application Submitted!</h2>
 <p>Your student pass application has been submitted for review.</p>
 <button className="metro-spass__btn" onClick={() => navigateToView("home")}>Back to Home</button>
 </div>
 </div>
 );
 }

 const discount = passType === "monthly" ? 0.7 : 0.6;
 const estimatedAmount = fare ? (parseFloat(value(fare.fare_amount)) * 30 * discount).toFixed(0) : null;

 return (
 <div className="metro-spass">
 <h1 className="metro-spass__title">Apply for Student Pass</h1>
 <div className="metro-spass__layout">
 <form className="metro-spass__form" onSubmit={handleSubmit}>
 {error && <div className="metro-spass__error">{error}</div>}
 <label className="metro-spass__label">Pass Type
 <select className="metro-spass__select" value={passType} onChange={e => setPassType(e.target.value)}>
 <option value="monthly">Monthly</option>
 <option value="quarterly">Quarterly</option>
 </select>
 </label>
 <label className="metro-spass__label">Source Station
 <select className="metro-spass__select" value={source} onChange={e => setSource(e.target.value)}>
 <option value="">Select station</option>
 {stations.map(s => <option key={value(s.sys_id)} value={value(s.sys_id)}>{display(s.station_name)}</option>)}
 </select>
 </label>
 <label className="metro-spass__label">Destination Station
 <select className="metro-spass__select" value={destination} onChange={e => setDestination(e.target.value)}>
 <option value="">Select station</option>
 {stations.map(s => <option key={value(s.sys_id)} value={value(s.sys_id)}>{display(s.station_name)}</option>)}
 </select>
 </label>
 <button className="metro-spass__btn" type="submit" disabled={submitting}>
 {submitting ? "Submitting..." : "Apply for Pass"}
 </button>
 </form>
 <div className="metro-spass__info">
 <h3>Pass Benefits</h3>
 <ul>
 <li>Unlimited rides between selected stations</li>
 <li>Up to {passType === "monthly" ? "30%" : "40%"} discounted fare</li>
 </ul>
 <h3>Validity</h3>
 <p>{passType === "monthly" ? "30 days" : "90 days"} from approval date</p>
 {estimatedAmount && <p className="metro-spass__amount">Estimated: ₹{estimatedAmount}</p>}
 </div>
 </div>
 </div>
 );
}
